{"filePath":"c:\Dev\Python_Web_Application\frontend\src\App.jsx","content":"import { useEffect, useState } from "react";
import { createNote, fetchNotes } from "./services/api";
import "./styles.css";

function App() {
  const [notes, setNotes] = useState([]);
  const [title, setTitle] = useState("");
  const [body, setBody] = useState("");
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState("");

  async function loadNotes() {
    setIsLoading(true);
    setError("");
    try {
      const data = await fetchNotes();
      setNotes(data);
    } catch (err) {
      setError(err.message || "Unable to load notes.");
    } finally {
      setIsLoading(false);
    }
  }

  useEffect(() => {
    loadNotes();
  }, []);

  async function handleSubmit(event) {
    event.preventDefault();
    setError("");
    try {
      await createNote({ title, body });
      setTitle("");
      setBody("");
      await loadNotes();
    } catch (err) {
      setError(err.message || "Unable to create note.");
    }
  }

  return (
    <main className="page">
      <header className="header">
        <h1>Notes Application</h1>
        <p>Week 1 baseline: create and list notes with FastAPI + SQLAlchemy.</p>
      </header>

      <section className="panel">
